func (s *Scanner) state1Whitespace() error {
	// We have an accepting state, update our bookkeeping.
	s.token = TokenWhitespace
	s.lexemeEndIdx = s.lexemePeekIdx

	nextByte := s.source[s.lexemePeekIdx]
	switch {
	case nextByte == '\t':
		s.state = 1
	case nextByte == '\n':
		s.state = 1
	case nextByte == '\r':
		s.state = 1
	case nextByte == ' ':
		s.state = 1
	default:
		return errInvalidByte
	}
	return nil
}

